import{_ as s,c as a,o as i,aj as n}from"./chunks/framework.BQevAs-I.js";const p=JSON.parse('{"title":"Benchmark (Experimental)","description":"Reproducible model comparison benchmarks for Torch-RecHub","frontmatter":{"title":"Benchmark (Experimental)","description":"Reproducible model comparison benchmarks for Torch-RecHub"},"headers":[],"relativePath":"tools/benchmark.md","filePath":"en/tools/benchmark.md"}'),t={name:"tools/benchmark.md"};function r(c,e,l,h,o,d){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="benchmark-experimental" tabindex="-1">Benchmark (Experimental) <a class="header-anchor" href="#benchmark-experimental" aria-label="Permalink to “Benchmark (Experimental)”">​</a></h1><p><code>benchmarks/</code> provides reproducible model comparisons under a fixed experimental protocol, separate from <code>examples/</code> (which focuses on tutorials).</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to “Quick Start”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Single config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/runner.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/configs/matching/ml_1m_mind.yaml</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run a group and produce a comparison table</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/suite.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --configs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;benchmarks/configs/matching/*.yaml&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  benchmark_results/suites/matching</span></span></code></pre></div><p>Each run writes <code>result.yaml</code> (metrics + run metadata), <code>summary.md</code>, and <code>model.pth</code>. The suite additionally writes <code>suite.md</code> — a side-by-side comparison table.</p><h2 id="supported-tasks" tabindex="-1">Supported Tasks <a class="header-anchor" href="#supported-tasks" aria-label="Permalink to “Supported Tasks”">​</a></h2><h3 id="matching-retrieval" tabindex="-1">Matching / Retrieval <a class="header-anchor" href="#matching-retrieval" aria-label="Permalink to “Matching / Retrieval”">​</a></h3><p>Dataset: MovieLens sample. Models: <code>MIND</code>, <code>YoutubeDNN</code>, <code>ComirecDR</code>, <code>ComirecSA</code>. Metrics: <code>Hit@K</code>, <code>Recall@K</code>, <code>NDCG@K</code>, <code>MRR@K</code>, <code>Precision@K</code>.</p><h3 id="ranking-ctr" tabindex="-1">Ranking / CTR <a class="header-anchor" href="#ranking-ctr" aria-label="Permalink to “Ranking / CTR”">​</a></h3><p>Dataset: Criteo sample. Models: <code>WideDeep</code>, <code>DeepFM</code>, <code>DCN</code>. Metrics configurable via <code>metrics: [AUC, LogLoss, ...]</code> (available: <code>AUC</code>, <code>LogLoss</code>, <code>Accuracy</code>, <code>MSE</code>).</p><h3 id="multi-task" tabindex="-1">Multi-Task <a class="header-anchor" href="#multi-task" aria-label="Permalink to “Multi-Task”">​</a></h3><p>Dataset: Census-Income sample, two tasks (income = cvr, marital status = ctr). Models: <code>ESMM</code>, <code>MMOE</code>, <code>PLE</code>. Metrics: <code>AUC[&lt;task&gt;]</code> per task + <code>AUC_mean</code> (NaN tasks excluded).</p><h2 id="baseline-regression-check" tabindex="-1">Baseline &amp; Regression Check <a class="header-anchor" href="#baseline-regression-check" aria-label="Permalink to “Baseline &amp; Regression Check”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/runner.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/configs/ranking/criteo_dcn.yaml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --check-baseline</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/suite.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --configs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;benchmarks/configs/ranking/*.yaml&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmark_results/suites/ranking</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --check-baseline</span></span></code></pre></div><p>Baselines live in <code>benchmarks/baselines/&lt;task&gt;.yaml</code>. Direction-aware: higher-is-better metrics (AUC, Hit, …) only fail when they drop; lower-is-better metrics (LogLoss, MSE) only fail when they rise.</p>`,15)])])}const m=s(t,[["render",r]]);export{p as __pageData,m as default};
